import chess

def evaluate_position(board):
    """
    Evaluates a chess position based on material, piece activity,
    control of the center, and pawn structure.

    Args:
        board (chess.Board): The chess board object representing the position.

    Returns:
        float: A numerical evaluation of the position. Positive values indicate
               an advantage for White, negative values indicate an advantage
               for Black.
    """

    # Material values
    piece_values = {
        chess.PAWN: 1,
        chess.KNIGHT: 3,
        chess.BISHOP: 3,
        chess.ROOK: 5,
        chess.QUEEN: 9,
        chess.KING: 0  # King's material value is not considered directly
    }

    # Initialize evaluation score
    evaluation = 0

    # Material count
    for piece_type in piece_values:
        evaluation += (len(board.pieces(piece_type, chess.WHITE)) -
                       len(board.pieces(piece_type, chess.BLACK))) * piece_values[piece_type]

    # Piece activity (number of legal moves)
    white_moves = board.legal_moves.copy()
    board.turn = chess.BLACK
    black_moves = board.legal_moves.copy()
    board.turn = chess.WHITE

    evaluation += 0.1 * (len(list(white_moves)) - len(list(black_moves)))

    # Control of the center (d4, e4, d5, e5 squares)
    center_squares = [chess.D4, chess.E4, chess.D5, chess.E5]
    for square in center_squares:
        if board.is_attacked_by(chess.WHITE, square):
            evaluation += 0.2
        if board.is_attacked_by(chess.BLACK, square):
            evaluation -= 0.2

    # Pawn structure (simplified - number of isolated pawns)
    white_isolated_pawns = 0
    black_isolated_pawns = 0

    for square in chess.SQUARES:
        piece = board.piece_at(square)
        if piece and piece.piece_type == chess.PAWN:
            if piece.color == chess.WHITE:
                is_isolated = True
                for file_offset in [-1, 1]:
                    if 0 <= chess.square_file(square) + file_offset <= 7:
                        neighbor_file = chess.square_file(square) + file_offset
                        for rank in range(8):
                            neighbor_square = chess.square(neighbor_file, rank)
                            neighbor_piece = board.piece_at(neighbor_square)
                            if neighbor_piece and neighbor_piece.piece_type == chess.PAWN and neighbor_piece.color == chess.WHITE:
                                is_isolated = False
                                break
                        if not is_isolated:
                            break
                if is_isolated:
                    white_isolated_pawns += 1
            else:  # Black pawn
                is_isolated = True
                for file_offset in [-1, 1]:
                    if 0 <= chess.square_file(square) + file_offset <= 7:
                        neighbor_file = chess.square_file(square) + file_offset
                        for rank in range(8):
                            neighbor_square = chess.square(neighbor_file, rank)
                            neighbor_piece = board.piece_at(neighbor_square)
                            if neighbor_piece and neighbor_piece.piece_type == chess.PAWN and neighbor_piece.color == chess.BLACK:
                                is_isolated = False
                                break
                        if not is_isolated:
                            break
                if is_isolated:
                    black_isolated_pawns += 1

    evaluation -= 0.3 * (white_isolated_pawns - black_isolated_pawns)

    # Checkmate and stalemate
    if board.is_checkmate():
        if board.turn == chess.WHITE:
            return -1000  # Black wins
        else:
            return 1000   # White wins
    elif board.is_stalemate() or board.is_insufficient_material() or board.is_seventyfive_move_rule() or board.is_fivefold_repetition() or board.is_repetition():
        return 0  # Draw

    return evaluation


